#include <bits/stdc++.h>
using namespace std;

bool cmp(pair<int,int> &p1, pair<int,int> &p2){
    return p1.second>p2.second;
}
int main() {
    vector<pair<int,int>> input={{4,2}, {2,3}, {3,4}, {1,5}, {2,7}};
    int k=3;
    sort(input.begin(),input.end(),cmp);

    priority_queue<int,vector<int>,greater<int>> positive;
    priority_queue<int> negative;
    int posSum=0;
    int negSum=0;

    for(int i=0;i<k;i++){
        positive.push(input[i].first);
        posSum+=input[i].first;
    }
    for(int i=0;i<k/2;i++){
        int minposElement=positive.top();
        positive.pop();
        posSum-=minposElement;
        negSum+=minposElement;
        negative.push(minposElement);
    }

    int res=(posSum-negSum)*input[k-1].second;

    for(int i=k;i<input.size();i++){
        int a=input[i].first;
        int smallestPositive=positive.top();
        int largestNegative=negative.top();
        if(a<smallestPositive && a>largestNegative){
            continue;
        }
        if(a>smallestPositive){
            posSum+=a-smallestPositive;
            positive.pop();
            positive.push(a);
        }
        else{
            negSum+=a-largestNegative;
            negative.pop();
            negative.push(a);
        }
        int temp=(posSum-negSum)*input[i].second;
        res=max(temp,res);
    }
    cout<<"Answer:- "<<res;
    return 0;
}
