include  <bits/stdc++.h>
using namespace std;

bool isPossible(string &str, int len, int K){
    int wS=0;       int wE=0;
    int one=0;      int zero=0;
    int ans=0;      int res=0;

    while(wE<len){
        if(str[wE]=='0'){
            zero++;
        }
        else{
            ans+=zero;
            one++;
        }
        wE++;
    }
    while(wE<str.size()){
        if(str[wS]=='0'){
            ans-=one;
            zero--;
        }
        else{
            one--;
        }
        if(str[wE]=='0'){
            zero++;
        }
        else{
            ans+=zero;
            one++;
        }
        res=max(res,ans);
        wS++;
        wE++;
    }
    return res>=K;
}

int helper(string &str, int K){
    int low=0;
    int high=str.size()-1;
    int res=-1;
    while(low<high){
        int mid=(high+low)/2;
        if(isPossible(str,mid,K)==true){
            high=mid-1;
            res=mid;
        }
        else{
            low=mid+1;
        }
    }
    return res;
}

int main() {
    string s;
    int k;
    cin>>s;
    cin>>k;
    cout<<"SHORTEST LEN IS:- "<<helper(s,k);
    return 0;
}
