include <bits/stdc++.h>
using namespace std;

class Graph{
    private:
        int V;
        list<pair<int,int>>* adj;
        map<pair<int,int>,int> mpp;
        vector<int> in;
        vector<int> out;
    public:
        Graph(int V){
            this->V=V;
            adj=new list<pair<int,int>>[V+1];
            in=vector<int>(V+1,INT_MAX);
            out=vector<int>(V+1,INT_MAX);
        }
        void addNodes(int u, int v, int wt){
            adj[u].push_back({v,wt});
            adj[v].push_back({u,0});  //backedge
            mpp[{u,v}]=wt;
            mpp[{v,u}]=0;
        }
        void findIN(int node, int par){
            int count=0;
            for(auto child: adj[node]){
                int childNode=child.first;
                int wt=child.second;
                if(childNode==par){
                    continue;
                } 
                count++;
                findIN(childNode,node);
		        in[node]=min(in[node],wt+in[childNode]);
	        }
	        if(count==0){
	            in[node]=0;
	        }
        }

        void findOUT(int node, int par){
            int mx1=INT_MAX;
            int mx2=INT_MAX;
            for(auto child: adj[node]){
                int childNode=child.first;
                int wt=child.second;
                if(childNode==par){
                    continue;
                }
                if(in[childNode]+wt<=mx1){
                    mx2=mx1;
                    mx1=in[childNode]+wt;
                }
                else if(in[childNode]+wt<mx2){
                    mx2=in[childNode]+wt;
                }
		        findOUT(childNode, node);
	        }
	        for(auto child: adj[node]){
                int childNode=child.first;
                int wt=child.second;
                if(childNode==par){
                    continue;
                }
                int use=mx1;
                if(mx1==in[childNode]+wt){
                    use=mx2;
                }
                out[childNode]=mpp[{childNode,node}]+min(out[node],use);
                findOUT(childNode,node);
	        }
        }
        void print(){
	        findIN(1, 0);
	        findOUT(1, 0);
            cout<<endl<<"IN-: ";
            for(auto e: in){
                cout<<e<<" ";
            }
            cout<<endl<<"OUT-: ";
            for(auto e: out){
                cout<<e<<" ";
            }
            cout<<endl;
        }
        void result(){
            int res=INT_MAX;
            for(int v=1;v<=V;v++){
                if(in[v]==INT_MAX || out[v]==INT_MAX){
                    continue;
                }
                res=min(res,in[v]+out[v]);
            }
            cout<<"Answer- "<<res;
        }
};

int main() {
