    Graph gr(V);
    gr.addNodes(1,2,5);
    gr.addNodes(1,3,10);
    gr.addNodes(2,4,2);
    gr.addNodes(3,5,3);
    gr.addNodes(6,5,2);
    gr.print();
    gr.result();
    return 0;
}
