#include<bits/stdc++.h>
using namespace std;



using ll = long long int;
typedef vector<ll>      vll ;


bool check(int len, vll &zeros, vll &ones, vll &seq, ll k) {
  int n = zeros.size() - 1;
  for(int i = 0; i<=n-len; i++) {
    ll total = (seq[i] - seq[i+len]) - (zeros[i] - zeros[i+len])*(ones[i+len]);
    if(total >= k) return true;
  }
  return false;
}
int BS(int s, int e, int k, vll &z, vll &o, vll &seq) {
  if(e-s == 1) {
    if(check(s,z,o,seq,k)) return s;
    return e;
  }
  int mid = (e+s)/2;
  if(check(mid,z,o,seq,k)) return BS(s,mid,k,z,o,seq);
  return BS(mid+1,e,k,z,o,seq);
}
void solver(string &s, int n , int k) {
  vector<ll> ones(n+1);
  vector<ll> zeros(n+1);
  vector<ll> seq(n+1);
  if(s[n-1] == '0') zeros[n-1] = 1;
  else ones[n-1] = 1;
  if(k==0) {
    cout<<1;
    return;
  }
  for(int i = n-2; i>=0; i--) {
    zeros[i] = zeros[i+1];
    ones[i] = ones[i+1];
    seq[i] = seq[i+1];
    if(s[i] == '0') {
      zeros[i]++;
      seq[i] += ones[i];
    }
    else ones[i]++;
  }
  if(k>seq[0]) {
    cout<<-1;
    return;
  }
  ll ans = BS(1,n,k,zeros,ones,seq);
  cout<<ans;
  return;
}

int main(){
    string s = "11011001";
    solver(s,8,2);
    return 0;
}

